export function getExerciseById(id, mapOrList) { if (!id) return null; if (mapOrList instanceof Map) return mapOrList.get(id) || null; return (mapOrList || []).find(item => item.id === id) || null; }
export function getAllMuscleFocus(exercises) { return Array.from(new Set(exercises.map(item => item.muscle_focus))).sort(); }
export function getAllMusclePortion(exercises) { return Array.from(new Set(exercises.map(item => item.muscle_portion).filter(Boolean))).sort(); }
export function getAllContractionTypes(exercises) { return Array.from(new Set(exercises.map(item => item.contraction_type).filter(Boolean))).sort(); }
export function scoreSimilarExercise(current, candidate) {
  let score = 0;
  if (!current || !candidate || current.id === candidate.id) return -1;
  if (candidate.muscle_focus === current.muscle_focus) score += 100;
  if (candidate.muscle_portion && candidate.muscle_portion === current.muscle_portion) score += 80;
  if (candidate.contraction_type && candidate.contraction_type === current.contraction_type) score += 50;
  if (candidate.type === current.type) score += 30;
  if (candidate.equipment === current.equipment) score += 15;
  if (candidate.difficulty === current.difficulty) score += 10;
  if ((current.secondary_muscles || []).includes(candidate.muscle_focus)) score += 6;
  if ((candidate.secondary_muscles || []).includes(current.muscle_focus)) score += 4;
  if ((current.similar_exercises || []).includes(candidate.id)) score += 40;
  return score;
}
export function getSimilarExercises(currentExercise, allExercises, limit = 6) {
  return allExercises.map(candidate => ({ candidate, score: scoreSimilarExercise(currentExercise, candidate) })).filter(item => item.score > 0).sort((a, b) => b.score - a.score).slice(0, limit).map(item => item.candidate);
}
